#!/usr/bin/env node

/**
 * Schema Write Guard — PreToolUse Hook
 *
 * Protects database schema files from full overwrites via the Write tool.
 * Agents must use Edit (with LINE#ID anchors) for surgical changes.
 *
 * Protection tiers:
 *
 *   LOCKED (Write AND Edit blocked — ALWAYS exit 2):
 *     - packages/database/schema/auth.ts     (Better Auth owned)
 *     - packages/database/drizzle/schema.ts   (auto-generated)
 *
 *   WRITE-PROTECTED (Write blocked, Edit allowed):
 *     - packages/database/schema/index.ts     (barrel, carefully managed)
 *     - packages/database/schema/app/*.ts     (app tables — use Edit)
 *     - packages/database/schema/app/index.ts (barrel — use Edit to add exports)
 *     - packages/database/migrations/*.sql    (generated by drizzle-kit)
 *
 * New file creation in schema/app/ is ALLOWED (Write to new path is fine).
 *
 * Toggle enforcement via env:
 *   SCHEMA_GUARD_MODE=soft  (default — warn only for WRITE-PROTECTED tier)
 *   SCHEMA_GUARD_MODE=hard  (block completely for all tiers)
 *   Note: LOCKED tier ALWAYS blocks regardless of mode.
 *
 * Exit codes:
 *   0 = ALLOW (tool proceeds)
 *   2 = BLOCK (stderr message shown to agent, tool does NOT execute)
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { basename, join } from "node:path";

// ── Configuration ──

const MODE = (process.env.SCHEMA_GUARD_MODE || "soft").toLowerCase();
const STATE_DIR = "/tmp/omo-schema-guard";
const STALE_MS = 10 * 60 * 1000; // 10 minutes — reset after inactivity

// ── Protection tiers ──

// LOCKED: Always blocked for BOTH Write and Edit. No exceptions.
const LOCKED_PATTERNS = [
  /\/schema\/auth\.ts$/, // Better Auth owned — DO NOT MODIFY
  /\/drizzle\/schema\.ts$/, // Auto-generated by drizzle-kit
];

// WRITE-PROTECTED: Write blocked (use Edit instead). Edit is allowed.
const WRITE_PROTECTED_PATTERNS = [
  /\/schema\/index\.ts$/, // Barrel file — update via Edit when adding tables
  /\/schema\/app\/[^/]+\.ts$/, // App table files — surgical Edit only
  /\/migrations\/[^/]+\.sql$/, // Migration SQL — generated by drizzle-kit
];

// ── Classification ──

function classifyFile(filePath) {
  if (!filePath) {
    return "unprotected";
  }
  for (const pattern of LOCKED_PATTERNS) {
    if (pattern.test(filePath)) {
      return "locked";
    }
  }
  for (const pattern of WRITE_PROTECTED_PATTERNS) {
    if (pattern.test(filePath)) {
      return "write-protected";
    }
  }
  return "unprotected";
}

// ── Helpers ──

function readStdin() {
  return new Promise((resolve) => {
    let data = "";
    process.stdin.setEncoding("utf8");
    process.stdin.on("data", (chunk) => {
      data += chunk;
    });
    process.stdin.on("end", () => {
      resolve(data);
    });
  });
}

function ensureStateDir() {
  try {
    if (!existsSync(STATE_DIR)) {
      mkdirSync(STATE_DIR, { recursive: true });
    }
  } catch {
    // Non-fatal
  }
}

function getState(sessionId) {
  if (!sessionId) {
    return null;
  }
  const safe = sessionId.replace(/[^a-zA-Z0-9_-]/g, "_");
  const stateFile = join(STATE_DIR, `${safe}.json`);
  try {
    if (existsSync(stateFile)) {
      const state = JSON.parse(readFileSync(stateFile, "utf8"));
      if (state.lastTimestamp && Date.now() - state.lastTimestamp > STALE_MS) {
        return null;
      }
      return state;
    }
  } catch {
    // Corrupted
  }
  return null;
}

function saveState(sessionId, state) {
  if (!sessionId) {
    return;
  }
  ensureStateDir();
  const safe = sessionId.replace(/[^a-zA-Z0-9_-]/g, "_");
  const stateFile = join(STATE_DIR, `${safe}.json`);
  try {
    writeFileSync(stateFile, JSON.stringify(state, null, 2));
  } catch {
    // Non-fatal
  }
}

// ── Guidance messages ──

function buildLockedGuidance(filePath, toolName) {
  const fileName = basename(filePath);
  const isAuth = /\/schema\/auth\.ts$/.test(filePath);
  const isDrizzleGenerated = /\/drizzle\/schema\.ts$/.test(filePath);

  const reason = isAuth
    ? "This file is BETTER AUTH OWNED. These tables are managed by Better Auth's migration system."
    : isDrizzleGenerated
      ? "This file is AUTO-GENERATED by drizzle-kit. Never edit it directly."
      : "This file is LOCKED.";

  const lines = [
    `⛔ LOCKED FILE — ${toolName.toUpperCase()} BLOCKED on ${fileName}`,
    "",
    `File: ${filePath}`,
    reason,
    "",
  ];

  if (isAuth) {
    lines.push(
      "═══ RULES FOR AUTH SCHEMA ═══",
      "",
      "• schema/auth.ts is LOCKED — no Write, no Edit, ever.",
      "• These tables are: user, session, account, verification,",
      "  organization, member, invitation, apikey.",
      "• Better Auth manages migrations for these tables.",
      "• If you need to extend user data, create an app table with a",
      "  foreign key to user.id in schema/app/<tablename>.ts.",
      ""
    );
  } else if (isDrizzleGenerated) {
    lines.push(
      "═══ RULES FOR GENERATED SCHEMA ═══",
      "",
      "• drizzle/schema.ts is auto-generated by `bun run db:generate`.",
      "• Never edit it manually — your changes will be overwritten.",
      "• To change schema: edit files in schema/app/ then run db:generate.",
      ""
    );
  }

  lines.push(
    "This block cannot be overridden. The file is permanently protected."
  );

  return lines.join("\n");
}

function buildWriteProtectedGuidance(filePath, violationCount) {
  const fileName = basename(filePath);
  const isBarrel = /\/schema\/(index|app\/index)\.ts$/.test(filePath);
  const isMigration = /\/migrations\//.test(filePath);
  const isEscalated = violationCount >= 3;

  let header;
  if (isEscalated) {
    header = `⛔ SCHEMA OVERWRITE BLOCKED — Repeated Violation (#${violationCount})`;
  } else if (violationCount === 2) {
    header = `⚠️  SCHEMA OVERWRITE WARNING — Second Attempt on ${fileName}`;
  } else {
    header = `⚠️  SCHEMA OVERWRITE WARNING — ${fileName} is a protected schema file`;
  }

  const lines = [
    header,
    "",
    `File: ${filePath}`,
    "",
    "Full rewrites of schema files risk destroying unrelated table definitions.",
    "",
  ];

  if (isMigration) {
    lines.push(
      "═══ MIGRATION FILES ARE GENERATED ═══",
      "",
      "• Migration SQL files are generated by `bun run db:generate`.",
      "• Never write or edit them manually.",
      "• To create a migration: modify schema/app/*.ts, then run db:generate.",
      ""
    );
  } else if (isBarrel) {
    lines.push(
      "═══ HOW TO UPDATE BARREL FILES ═══",
      "",
      "• Use Edit to append a new export line:",
      '  edit({ filePath: "...", edits: [{ op: "append", pos: "LINE#ID", lines: [\'export * from "./<tablename>";\'] }] })',
      "",
      "• For schema/index.ts: also add the table to the `schema` object.",
      ""
    );
  } else {
    lines.push(
      "═══ WHAT TO DO INSTEAD ═══",
      "",
      "1. Verify current state:",
      `   git show HEAD -- ${filePath}`,
      "",
      "2. Use the Edit tool with LINE#ID anchors:",
      '   edit({ filePath: "...", edits: [{ op: "append", pos: "LINE#ID", lines: [...] }] })',
      "",
      "3. If the file is corrupted, restore first:",
      `   git checkout HEAD -- ${filePath}`,
      "",
      "4. Batch ALL changes into ONE edit call (multiple edits = hash corruption risk)",
      ""
    );
  }

  if (isEscalated) {
    lines.push(
      "═══ ESCALATION REQUIRED ═══",
      "",
      "You have attempted to overwrite this schema file 3+ times.",
      "This suggests a deeper issue. Before proceeding:",
      "  - Consult Oracle: task({ subagent_type: 'oracle', prompt: 'Schema edit guidance...' })",
      `  - Or restore: git checkout HEAD -- ${filePath}`,
      ""
    );
  }

  lines.push(
    "NEVER use Write on schema files. Use Edit with surgical LINE#ID changes."
  );

  return lines.join("\n");
}

// ── Main ──

async function main() {
  const raw = await readStdin();

  let input;
  try {
    input = JSON.parse(raw);
  } catch {
    process.exit(0); // Fail open on parse error
  }

  const toolName = (input.tool_name || "").toLowerCase();

  // Only intercept Write tool
  if (toolName !== "write") {
    process.exit(0);
  }

  const sessionId = input.session_id;
  const toolInput = input.tool_input || {};
  const filePath = toolInput.filePath || toolInput.file_path || "";

  const tier = classifyFile(filePath);

  // ── Unprotected — allow silently ──
  if (tier === "unprotected") {
    process.exit(0);
  }

  // ── LOCKED tier — ALWAYS block, no exceptions ──
  if (tier === "locked") {
    process.stderr.write(buildLockedGuidance(filePath, toolName) + "\n");
    process.exit(2); // HARD BLOCK
  }

  // ── WRITE-PROTECTED tier ──

  // Allow new file creation in schema/app/ (e.g., new table file)
  if (!existsSync(filePath) && /\/schema\/app\//.test(filePath)) {
    process.exit(0);
  }

  // Track violations
  const state = getState(sessionId) || {
    violations: {},
    lastTimestamp: 0,
  };

  const fileKey = filePath.replace(/\//g, "__");
  state.violations[fileKey] = (state.violations[fileKey] || 0) + 1;
  state.lastTimestamp = Date.now();
  saveState(sessionId, state);

  const violationCount = state.violations[fileKey];
  const guidance = buildWriteProtectedGuidance(filePath, violationCount);

  // Always hard-block on 3+ violations regardless of mode
  if (violationCount >= 3) {
    process.stderr.write(guidance + "\n");
    process.exit(2);
  }

  // Mode-based behavior for 1st and 2nd violations
  if (MODE === "hard") {
    process.stderr.write(guidance + "\n");
    process.exit(2);
  }

  // Soft mode — warn but allow
  process.stderr.write(guidance + "\n");
  process.exit(0);
}

main().catch(() => {
  process.exit(0); // Fail open on errors
});
